mapper.select:
SELECT U.ID AS userId, U.NAME AS name, U.NICKNAME AS nickname, U.EMAIL AS email, U.GENDER AS gender, U.LEVEL AS level, U.JOBS AS jobs, U.MBTI AS mbti FROM USERS U WHERE U.STATUS = 'ACTIVE' and U.ID NOT IN ( SELECT A.USER_ID FROM SESSION_APPLICATIONS A WHERE A.SESSION_ID = #{sessionId} AND A.STATUS != 'CANCELED' )
AND ( U.NAME LIKE '%' || #{query} || '%' OR U.NICKNAME LIKE '%' || #{query} || '%' )
ORDER BY U.ID ASC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM TABLE_ASSIGNMENTS
WHERE SESSION_ID = #{sessionId}

mapper.update:
UPDATE SESSION_APPLICATIONS
SET
STATUS = 'CANCELED',
UPDATED_AT = #{updatedAt}
WHERE 1 = 1
and ID = #{applicationId}
and session_id = #{sessionId}

UPDATE SESSIONS
SET
STATUS = 'CLOSED',
UPDATED_AT = #{now}
WHERE STATUS = 'OPEN'
AND STARTS_AT < #{now}
